def search_substring(records, fieldnames, query, norm=True):
    query_n = normalize_ar(query) if norm else query
    results = []
    for rec in records:
        for fn in fieldnames:
            txt = rec.get(fn)
            if not txt:
                continue
            tnorm = normalize_ar(txt) if norm else txt
            if query_n and query_n in tnorm:
                results.append((rec, fn))
                break
    return results

