def search_tokens_and(tokens):
    res = []
    rtoks = [normalize_ar(t) for t in tokens]
    for rec in hd:
        for fn in ['Matn','hadithTxt']:
            t = rec.get(fn) or ''
            norm = normalize_ar(t)
            if all(tok in norm for tok in rtoks):
                res.append(rec)
                break
    return res

